#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int a0[n], a1[n], a2[n], a3[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d %d", &a0[i], &a1[i], &a2[i], &a3[i]);
        }
        int q;
        scanf("%d", &q);
        while (q--) {
            int t;
            scanf("%d", &t);
            int min_val = 2e9;
            int min_idx = -1;
            for (int i = 0; i < n; i++) {
                int val = a0[i] + a1[i] * t + a2[i] * t * t + a3[i] * t * t * t;
                if (val < min_val) {
                    min_val = val;
                    min_idx = i;
                }
            }
            printf("%d\n", min_idx + 1);
        }
    }
    return 0;
}

