import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a0 = new int[n];
            int[] a1 = new int[n];
            int[] a2 = new int[n];
            int[] a3 = new int[n];
            for (int i = 0; i < n; i++) {
                a0[i] = sc.nextInt();
                a1[i] = sc.nextInt();
                a2[i] = sc.nextInt();
                a3[i] = sc.nextInt();
            }
            int q = sc.nextInt();
            while (q-- > 0) {
                int t = sc.nextInt();
                int min_val = Integer.MAX_VALUE;
                int min_idx = -1;
                for (int i = 0; i < n; i++) {
                    int val = a0[i] + a1[i] * t + a2[i] * t * t + a3[i] * t * t * t;
                    if (val < min_val) {
                        min_val = val;
                        min_idx = i;
                    }
                }
                System.out.println(min_idx + 1);
            }
        }
    }
}

